    PatternTokens = [<<"dd"/utf8>>, <<"remote"/utf8>>, <<"thread"/utf8>>, <<"{thread_id}"/utf8>>, <<"control"/utf8>>],
    case length(Tokens) =:= length(PatternTokens) of
        false -> error;
        true ->
            Pairs = lists:zip(PatternTokens, Tokens),
            LiteralsOk = lists:all(fun({P, S}) ->
                case is_placeholder(P) of
                    true -> true;
                    false -> P =:= S
                end
            end, Pairs),
            case LiteralsOk of
                false -> error;
                true ->
                    {ok, #{thread_id => extract_param(Pairs, <<"{thread_id}"/utf8>>)}}
            end
    end.

